        [DataRow("Lee", "A", "Lee, A", DisplayName = "Single character first name")]
        public void FullName_ReturnsLastNameCommaFirstMidName(string lastName, string firstName, string expected)
        {
            // Arrange
            var student = new Student { LastName = lastName, FirstMidName = firstName };

            // Act
            var result = student.FullName;

            // Assert
