using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 5);
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_SetsTotalPages()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 5);
            Assert.AreEqual(2, list.TotalPages);
        }

        [TestMethod]
        [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
        [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages (rounds up)")]
        [DataRow(1, 5, 1, DisplayName = "1 item, page size 5 = 1 page")]
        [DataRow(0, 5, 0, DisplayName = "0 items, page size 5 = 0 pages")]
        [DataRow(5, 5, 1, DisplayName = "5 items, page size 5 = 1 page")]
        [DataRow(6, 5, 2, DisplayName = "6 items, page size 5 = 2 pages")]
        public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 10, 20, 30 };
            var list = new PaginatedList<int>(items, 3, 1, 10);

            Assert.AreEqual(3, list.Count);
            Assert.AreEqual(10, list[0]);
            Assert.AreEqual(20, list[1]);
            Assert.AreEqual(30, list[2]);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 5);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_PagesCorrectly()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.AreEqual(4, result.TotalPages);
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
        }

        [TestMethod]
        public void Create_FirstPage_TakesFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
        }

        [TestMethod]
        public void Create_LastPage_TakesRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(3, result.PageIndex);
            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(0, result.TotalPages);
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(1, result.PageIndex);
        }

        [TestMethod]
        public void Create_SingleItem_SinglePage()
        {
            var source = new[] { 42 }.AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(1, result.TotalPages);
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(42, result[0]);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain the static queue to avoid interference between tests
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesNotification()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("42"));
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _sut.ReceiveNotification();
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void SendNotification_CREATE_GeneratesCorrectMessage()
        {
            _sut.SendNotification("Course", "1", "Chemistry", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UPDATE_GeneratesCorrectMessage()
        {
            _sut.SendNotification("Course", "1", "Chemistry", EntityOperation.UPDATE);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DELETE_GeneratesCorrectMessage()
        {
            _sut.SendNotification("Course", "1", "Chemistry", EntityOperation.DELETE);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("Course 'Chemistry' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_CREATE_UsesIdFormat()
        {
            _sut.SendNotification("Course", "42", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("New Course (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UPDATE_UsesIdFormat()
        {
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("Course (ID: 42) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_DELETE_UsesIdFormat()
        {
            _sut.SendNotification("Course", "42", EntityOperation.DELETE);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("Course (ID: 42) has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DefaultsToSystemUser()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_ExplicitNullUser_DefaultsToSystem()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = System.DateTime.Now;
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            var after = System.DateTime.Now;

            var notification = _sut.ReceiveNotification();

            Assert.IsTrue(notification.CreatedAt >= before);
            Assert.IsTrue(notification.CreatedAt <= after);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // Should complete without exception
        }

        [TestMethod]
        public void SendAndReceive_MultipleNotifications_FIFO()
        {
            _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

            var n1 = _sut.ReceiveNotification();
            var n2 = _sut.ReceiveNotification();
            var n3 = _sut.ReceiveNotification();
            var n4 = _sut.ReceiveNotification();

            Assert.AreEqual("A", n1.EntityType);
            Assert.AreEqual("B", n2.EntityType);
            Assert.AreEqual("C", n3.EntityType);
            Assert.IsNull(n4);
        }

        [TestMethod]
        public void SendNotification_IsRead_DefaultFalse()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            // Tests the 2-parameter overload: SendNotification(entityType, entityId, operation, userName)
            _sut.SendNotification("Instructor", "5", EntityOperation.UPDATE, "TestUser");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Instructor", notification.EntityType);
            Assert.AreEqual("5", notification.EntityId);
            Assert.AreEqual("UPDATE", notification.Operation);
            Assert.AreEqual("TestUser", notification.CreatedBy);
        }
    }
}

