        }

        [TestMethod]
        public void Initialize_IsIdempotent()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context);

            // Should still have same count after second call
            Assert.AreEqual(8, context.Students.Count());
            Assert.AreEqual(5, context.Instructors.Count());
            Assert.AreEqual(4, context.Departments.Count());
            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_StudentNames_AreCorrect()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.IsTrue(context.Students.Any(s => s.LastName == "Alexander" && s.FirstMidName == "Carson"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Alonso" && s.FirstMidName == "Meredith"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Anand" && s.FirstMidName == "Arturo"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Barzdukas" && s.FirstMidName == "Gytis"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Li" && s.FirstMidName == "Yan"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Justice" && s.FirstMidName == "Peggy"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Norman" && s.FirstMidName == "Laura"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Olivetto" && s.FirstMidName == "Nino"));
        }

        [TestMethod]
        public void Initialize_InstructorNames_AreCorrect()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Abercrombie" && i.FirstMidName == "Kim"));
            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Fakhouri" && i.FirstMidName == "Fadi"));
            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Harui" && i.FirstMidName == "Roger"));
            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Kapoor" && i.FirstMidName == "Candace"));
            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Zheng" && i.FirstMidName == "Roger"));
        }

        [TestMethod]
        public void Initialize_DepartmentNames_AreCorrect()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.IsTrue(context.Departments.Any(d => d.Name == "English"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Mathematics"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Engineering"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Economics"));
        }

        [TestMethod]
        public void Initialize_CourseCredits_AreCorrect()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
            Assert.AreEqual(3, chemistry.Credits);

            var calculus = context.Courses.Single(c => c.Title == "Calculus");
            Assert.AreEqual(4, calculus.Credits);
        }

        [TestMethod]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            var departments = context.Departments.ToList();
            Assert.IsTrue(departments.All(d => d.InstructorID != null));
        }

        [TestMethod]
        public void Initialize_EnrollmentsHaveGrades()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            // At least some enrollments should have grades
            var withGrades = context.Enrollments.Count(e => e.Grade != null);
            Assert.IsTrue(withGrades > 0);

            // Arturo Anand's Chemistry enrollment has no grade
            var anandId = context.Students.Single(s => s.LastName == "Anand").ID;
            var chemistryId = context.Courses.Single(c => c.Title == "Chemistry").CourseID;
            var noGradeEnrollment = context.Enrollments.Single(e => e.StudentID == anandId && e.CourseID == chemistryId);
            Assert.IsNull(noGradeEnrollment.Grade);
        }
    }
}

