using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.TestHelpers;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new HomeController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void About_EmptyDatabase_ReturnsViewWithEmptyModel()
        {
            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void About_WithSeededData_ReturnsViewWithEnrollmentDateGroups()
        {
            DbInitializer.Initialize(_context);

            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Count > 0);
            Assert.IsTrue(model.All(g => g.StudentCount > 0));
        }

        [TestMethod]
        public void About_WithSeededData_GroupsByEnrollmentDate()
        {
            DbInitializer.Initialize(_context);

            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // There are 8 students with 5 distinct enrollment dates
            Assert.AreEqual(5, model.Count);

            // Total students across all groups should be 8
            var totalStudents = model.Sum(g => g.StudentCount);
            Assert.AreEqual(8, totalStudents);
        }

        [TestMethod]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            _controller.Contact();

            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewResult()
        {
            var result = _controller.Unauthorized();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Unauthorized_SetsViewBagMessage()
        {
            _controller.Unauthorized();

            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.TestHelpers;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                _controller.ControllerContext.HttpContext,
                Mock.Of<ITempDataProvider>());
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private void SeedStudents()
        {
            _context.Students.AddRange(
                new Student { FirstMidName = "Alice", LastName = "Adams", EnrollmentDate = new DateTime(2023, 1, 15) },
                new Student { FirstMidName = "Bob", LastName = "Brown", EnrollmentDate = new DateTime(2022, 9, 1) },
                new Student { FirstMidName = "Charlie", LastName = "Clark", EnrollmentDate = new DateTime(2023, 9, 1) }
            );
            _context.SaveChanges();
        }

        // --- Index Tests ---

        [TestMethod]
        public void Index_DefaultSort_ReturnsViewWithStudentsOrderedByLastName()
        {
            SeedStudents();

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
            Assert.AreEqual("Adams", model[0].LastName);
            Assert.AreEqual("Brown", model[1].LastName);
            Assert.AreEqual("Clark", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_ReturnsStudentsInDescendingOrder()
        {
            SeedStudents();

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Clark", model[0].LastName);
            Assert.AreEqual("Brown", model[1].LastName);
            Assert.AreEqual("Adams", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_ReturnsStudentsOrderedByDate()
        {
            SeedStudents();

            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Brown", model[0].LastName);  // 2022-09-01
        }

        [TestMethod]
        public void Index_DateDescSort_ReturnsStudentsOrderedByDateDescending()
        {
            SeedStudents();

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            // 2023-09-01 (Clark) and 2023-01-15 (Adams) both in 2023, Clark has later date
            Assert.AreEqual("Clark", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersResults()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Brown", null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Brown", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersResults()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Adams", model[0].LastName);
        }

        [TestMethod]
        public void Index_NewSearch_ResetsPageToOne()
        {
            SeedStudents();

            _controller.Index(null, null, "SomeSearch", null);

            // When searchString is not null, page should be set to 1
            // ViewBag.CurrentFilter should be set
            Assert.AreEqual("SomeSearch", _controller.ViewBag.CurrentFilter);
        }

        [TestMethod]
        public void Index_NoSearchString_UsesCurrentFilter()
        {
            SeedStudents();

            _controller.Index(null, "Brown", null, null);

            Assert.AreEqual("Brown", _controller.ViewBag.CurrentFilter);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            SeedStudents();

            _controller.Index(null, null, null, null);

            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_NameDescSort_SetsNameSortParmToEmpty()
        {
            SeedStudents();

            _controller.Index("name_desc", null, null, null);

            Assert.AreEqual("", _controller.ViewBag.NameSortParm);
        }

        [TestMethod]
        public void Index_DateSort_SetsDateSortParmToDateDesc()
        {
            SeedStudents();

            _controller.Index("Date", null, null, null);

            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
        }

        // --- Details Tests ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            SeedStudents();
            var studentId = _context.Students.First().ID;

            var result = _controller.Details(studentId) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(studentId, model.ID);
        }

        // --- Create GET Tests ---

        [TestMethod]
        public void Create_GET_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create POST Tests ---

        [TestMethod]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        }

        [TestMethod]
        public void Create_POST_ValidStudent_SavesStudentToDatabase()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.AreEqual(1, _context.Students.Count());
            var saved = _context.Students.First();
            Assert.AreEqual("Test", saved.FirstMidName);
            Assert.AreEqual("Student", saved.LastName);
        }

        [TestMethod]
        public void Create_POST_DefaultDate_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            Assert.IsFalse(_controller.ModelState.IsValid);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(student);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        // --- Edit GET Tests ---

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        [TestMethod]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // --- Edit POST Tests ---

        [TestMethod]
        public void Edit_POST_ValidStudent_RedirectsToIndex()
        {
            SeedStudents();
            var existing = _context.Students.First();
            // Detach to avoid tracking conflicts
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedStudent = new Student
            {
                ID = existing.ID,
                FirstMidName = "UpdatedFirst",
                LastName = "UpdatedLast",
                EnrollmentDate = new DateTime(2023, 6, 15)
            };

            var result = _controller.Edit(editedStudent);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        }

        [TestMethod]
        public void Edit_POST_DefaultDate_AddsModelError()
        {
            SeedStudents();
            var existing = _context.Students.First();

            var student = new Student
            {
                ID = existing.ID,
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        [TestMethod]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Edit(student);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        // --- Delete GET Tests ---

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewWithStudent()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        [TestMethod]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // --- DeleteConfirmed Tests ---

        [TestMethod]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            SeedStudents();
            var student = _context.Students.First();
            var initialCount = _context.Students.Count();

            var result = _controller.DeleteConfirmed(student.ID);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
            Assert.AreEqual(initialCount - 1, _context.Students.Count());
        }

        [TestMethod]
        public void Index_EmptyDatabase_ReturnsViewWithEmptyList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.Logging;
using Moq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.TestHelpers;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _controller;
        private Mock<IWebHostEnvironment> _mockEnv;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns("/fakepath/wwwroot");
            _mockEnv.Setup(e => e.ContentRootPath).Returns("/fakepath");

            _controller = new CoursesController(_context, _mockEnv.Object, Mock.Of<ILogger<CoursesController>>());
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private Department SeedDepartment()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        private Course SeedCourse(int departmentId)
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = departmentId
            };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        // --- Index Tests ---

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
        {
            var dept = SeedDepartment();
            SeedCourse(dept.DepartmentID);

            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Chemistry", model[0].Title);
        }

        [TestMethod]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        // --- Details Tests ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var dept = SeedDepartment();
            var course = SeedCourse(dept.DepartmentID);

            var result = _controller.Details(course.CourseID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual(course.CourseID, model.CourseID);
            Assert.AreEqual("Chemistry", model.Title);
        }

        // --- Create GET Tests ---

        [TestMethod]
        public void Create_GET_ReturnsViewWithCourse()
        {
            SeedDepartment();

            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
        }

        [TestMethod]
        public void Create_GET_PopulatesDepartmentSelectList()
        {
            SeedDepartment();

            _controller.Create();

            Assert.IsNotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Create POST Tests ---

        [TestMethod]
        public void Create_POST_ValidCourse_RedirectsToIndex()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 2000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        }

        [TestMethod]
        public void Create_POST_ValidCourse_SavesToDB()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 2000,
